-- Check the exact billingPlatform column value and understand the column name
SELECT s.externalId, s.planName, s.monthlyCost, s.billingPlatform, s.costSource
FROM services s
WHERE LOWER(s.planName) LIKE '%ucxcel webex basic%'
  AND s.status != 'terminated'
LIMIT 5;

-- Also check what the column is actually named in the services table
SHOW COLUMNS FROM services LIKE '%billing%';
SHOW COLUMNS FROM services LIKE '%cost%';

